mapper.select:
SELECT COUNT(*) > 0
FROM reviews
WHERE user_id = #{userId}
  AND movie_id = #{movieId}

mapper.insert:
INSERT INTO reviews (
    user_id, movie_id, rating, content,
    is_deleted, is_blinded, spoiler, like_count,
    created_at, updated_at, created_by, updated_by
) VALUES (
    #{user.userId}, #{movieId}, #{rating}, #{content},
    false, false, #{spoiler}, 0,
    NOW(), NOW(), #{createdBy}, #{updatedBy}
)

mapper.update:
UPDATE reviews
SET rating     = #{rating},
    content    = #{content},
    updated_at = NOW(),
    updated_by = #{updatedBy}
WHERE review_id = #{reviewId}
